import { useState } from "react";

import Login from "./components/auth/Login";
import Signup from "./components/auth/Signup";

import AdminLayout from "./components/layouts/AdminLayout";
import TechnicianLayout from "./components/layouts/TechnicianLayout";

import AdminDashboard from "./components/dashboards/AdminDashboard";
import TechnicianDashboard from "./components/dashboards/TechnicianDashboard";
import UserDashboard from "./components/dashboards/UserDashboard";

function App() {
  const [page, setPage] = useState("login");
  const [isAuth, setIsAuth] = useState(false);
  const [userRole, setUserRole] = useState(null);
  const [userData, setUserData] = useState(null);

  const loginSuccess = (role, email) => {
    setIsAuth(true);
    setUserRole(role);
    setUserData({ role, email });
  };

  const signupSuccess = (data) => {
    setIsAuth(true);
    setUserRole(data.role);
    setUserData(data);
  };

  const logout = () => {
    setIsAuth(false);
    setUserRole(null);
    setUserData(null);
    setPage("login");
  };

  // ---------------- AUTH SCREENS ----------------
  if (!isAuth) {
    return page === "login" ? (
      <Login
        onLoginSuccess={loginSuccess}
        goToSignup={() => setPage("signup")}
      />
    ) : (
      <Signup
        onSignupSuccess={signupSuccess}
        goToLogin={() => setPage("login")}
      />
    );
  }

  // ---------------- ROLE-BASED LAYOUTS ----------------
  if (userRole === "admin") {
    return (
      <AdminLayout userData={userData} onLogout={logout}>
        <AdminDashboard />
      </AdminLayout>
    );
  }

  if (userRole === "technician") {
    return (
      <TechnicianLayout userData={userData} onLogout={logout}>
        <TechnicianDashboard userData={userData} />
      </TechnicianLayout>
    );
  }

  // ---------------- DEFAULT USER ----------------
  return <UserDashboard userData={userData} onLogout={logout} />;
}
import { BrowserRouter, Routes, Route } from "react-router-dom";
import AssignedSystems from "./technician/AssignedSystems";
import SystemDiagnosis from "./technician/SystemDiagnosis";





export default App;
